"""
Parameterized generator for GH881_pymc_7858.

Source PR:    https://github.com/pymc-devs/pymc/pull/7858
Source Issue: https://github.com/pymc-devs/pymc/issues/7857

Seed varies: renames 'access' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH881_pymc_7858'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH881_pymc_7858'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('access', 'access' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH881_pymc_7858',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7858,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7858",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/pytensorf.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport warnings\n\nfrom collections.abc import Iterable, Sequence\nfrom typing import cast\n\nimport numpy as np\nimport pandas as pd\nimport pytensor\nimport pytensor.tensor as pt\nimport scipy.sparse as sps\n\nfrom pytensor.compile import Function, Mode, get_mode\nfrom pytensor.compile.builders import OpFromGraph\nfrom pytensor.gradient import grad\nfrom pytensor.graph import Type, rewrite_graph\nfrom pytensor.graph.basic import (\n    Apply,\n    Constant,\n    Variable,\n    clone_get_equiv,\n    equal_computations,\n    graph_inputs,\n)\nfrom pytensor.graph.fg import FunctionGraph, Output\nfrom pytensor.scalar.basic import Cast\nfrom pytensor.scan.op import Scan\nfrom pytensor.tensor.basic import _as_tensor_variable\nfrom pytensor.tensor.elemwise import Elemwise\nfrom pytensor.tensor.random.op import RandomVariable\nfrom pytensor.tensor.random.type import RandomType\nfrom pytensor.tensor.random.var import RandomGeneratorSharedVariable\nfrom pytensor.tensor.rewriting.basic import topo_unconditional_constant_folding\nfrom pytensor.tensor.rewriting.shape import ShapeFeature\nfrom pytensor.tensor.sharedvar import SharedVariable, TensorSharedVariable\nfrom pytensor.tensor.subtensor import AdvancedIncSubtensor, AdvancedIncSubtensor1\nfrom pytensor.tensor.variable import TensorVariable\n\nfrom pymc.exceptions import NotConstantValueError\nfrom pymc.util import makeiter\nfrom pymc.vartypes import continuous_types, isgenerator, typefilter\n\nPotentialShapeType = int | np.ndarray | Sequence[int | Variable] | TensorVariable\n\n__all__ = [\n    "CallableTensor",\n    "compile",\n    "cont_inputs",\n    "convert_data",\n    "convert_observed_data",\n    "floatX",\n    "gradient",\n    "hessian",\n    "hessian_diag",\n    "inputvars",\n    "intX",\n    "jacobian",\n    "join_nonshared_inputs",\n    "make_shared_replacements",\n]\n\n\ndef convert_observed_data(data) -> np.ndarray | Variable:\n    """Convert user provided dataset to accepted formats."""\n    if isgenerator(data):\n        raise TypeError("Data passed to `observed` cannot be a generator.")\n    return convert_data(data)\n\n\ndef convert_data(data) -> np.ndarray | Variable:\n    ret: np.ndarray | Variable\n    if hasattr(data, "to_numpy") and hasattr(data, "isnull"):\n        # typically, but not limited to pandas objects\n        vals = data.to_numpy()\n        null_data = data.isnull()\n        if hasattr(null_data, "to_numpy"):\n            # pandas Series\n            mask = null_data.to_numpy()\n        else:\n            # pandas Index\n            mask = null_data\n        if mask.any():\n            # there are missing values\n            ret = np.ma.MaskedArray(vals, mask)\n        else:\n            ret = vals\n    elif isinstance(data, np.ndarray):\n        if isinstance(data, np.ma.MaskedArray):\n            if not data.mask.any():\n                # empty mask\n                ret = data.filled()\n            else:\n                # already masked and rightly so\n                ret = data\n        else:\n            # already a ndarray, but not masked\n            mask = np.isnan(data)\n            if np.any(mask):\n                ret = np.ma.MaskedArray(data, mask)\n            else:\n                # no masking required\n                ret = data\n    elif isinstance(data, Variable):\n        ret = data\n    elif sps.issparse(data):\n        ret = data\n    else:\n        ret = np.asarray(data)\n\n    # Data without dtype info is converted to float arrays by default.\n    # This is the most common case for simple examples.\n    if not hasattr(data, "dtype"):\n        return floatX(ret)\n    # Otherwise we only convert the precision.\n    return smarttypeX(ret)\n\n\n@_as_tensor_variable.register(pd.Series)\n@_as_tensor_variable.register(pd.DataFrame)\ndef dataframe_to_tensor_variable(df: pd.DataFrame, *args, **kwargs) -> TensorVariable:\n    return pt.as_tensor_variable(df.to_numpy(), *args, **kwargs)\n\n\ndef extract_obs_data(x: TensorVariable) -> np.ndarray:\n    """Extract data from observed symbolic variables.\n\n    Raises\n    ------\n    TypeError\n\n    """\n    # TODO: These data functions should be in data.py or model/core.py\n    from pymc.data import MinibatchOp\n\n    if isinstance(x, Constant):\n        return x.data\n    if isinstance(x, SharedVariable):\n        return x.get_value()\n    if x.owner is not None:\n        if isinstance(x.owner.op, Elemwise) and isinstance(x.owner.op.scalar_op, Cast):\n            array_data = extract_obs_data(x.owner.inputs[0])\n            return array_data.astype(x.type.dtype)\n        if isinstance(x.owner.op, MinibatchOp):\n            return extract_obs_data(x.owner.inputs[x.owner.outputs.index(x)])\n        if isinstance(x.owner.op, AdvancedIncSubtensor | AdvancedIncSubtensor1):\n            array_data = extract_obs_data(x.owner.inputs[0])\n            mask_idx = tuple(extract_obs_data(i) for i in x.owner.inputs[2:])\n            mask = np.zeros_like(array_data)\n            mask[mask_idx] = 1\n            return np.ma.MaskedArray(array_data, mask)\n\n    from pymc.logprob.utils import rvs_in_graph\n\n    if not inputvars(x) and not rvs_in_graph(x):\n        cheap_eval_mode = Mode(linker="py", optimizer=None)\n        return x.eval(mode=cheap_eval_mode)\n\n    raise TypeError(f"Data cannot be extracted from {x}")\n\n\ndef replace_vars_in_graphs(\n    graphs: Iterable[Variable],\n    replacements: dict[Variable, Variable],\n) -> list[Variable]:\n    """Replace variables in graphs.\n\n    Graphs are cloned and not modified in place, unless the replacement expressions include variables from the original graphs.\n\n    """\n    # Clone graphs and get equivalences\n    inputs = [i for i in graph_inputs(graphs) if not isinstance(i, Constant)]\n    memo = {k: k for k in replacements.keys()}\n    equiv = clone_get_equiv(inputs, graphs, False, False, memo)\n\n    fg = FunctionGraph(\n        [equiv[i] for i in inputs],\n        [equiv[o] for o in graphs],\n        clone=False,\n    )\n\n    # Filter replacement keys that are actually present in the graph\n    vars = fg.variables\n    final_replacements = tuple((k, v) for k, v in replacements.items() if k in vars)\n\n    # Replacements have to be done in reverse topological order so that nested\n    # expressions get recursively replaced correctly\n    toposort_replace(fg, final_replacements, reverse=True)\n\n    return list(fg.outputs)\n\n\ndef inputvars(a):\n    """\n    Get the inputs into PyTensor variables.\n\n    Parameters\n    ----------\n        a: PyTensor variable\n\n    Returns\n    -------\n        r: list of tensor variables that are inputs\n    """\n    return [\n        v\n        for v in graph_inputs(makeiter(a))\n        if isinstance(v, Variable) and not isinstance(v, Constant | SharedVariable)\n    ]\n\n\ndef cont_inputs(a):\n    """\n    Get the continuous inputs into PyTensor variables.\n\n    Parameters\n    ----------\n        a: PyTensor variable\n\n    Returns\n    -------\n        r: list of tensor variables that are continuous inputs\n    """\n    return typefilter(inputvars(a), continuous_types)\n\n\ndef floatX(X):\n    """Convert a PyTensor tensor or numpy array to pytensor.config.floatX type."""\n    try:\n        return X.astype(pytensor.config.floatX)\n    except AttributeError:\n        # Scalar passed\n        return np.asarray(X, dtype=pytensor.config.floatX)\n\n\n_conversion_map = {"float64": "int32", "float32": "int16", "float16": "int8", "float8": "int8"}\n\n\ndef intX(X):\n    """Convert a pytensor tensor or numpy array to pytensor.tensor.int32 type."""\n    intX = _conversion_map[pytensor.config.floatX]\n    try:\n        return X.astype(intX)\n    except AttributeError:\n        # Scalar passed\n        return np.asarray(X, dtype=intX)\n\n\ndef smartfloatX(x):\n    """Convert numpy float values to floatX and leaves values of other types unchanged."""\n    if str(x.dtype).startswith("float"):\n        x = floatX(x)\n    return x\n\n\ndef smarttypeX(x):\n    if str(x.dtype).startswith("float"):\n        x = floatX(x)\n    elif str(x.dtype).startswith("int"):\n        x = intX(x)\n    return x\n\n\n"""\nPyTensor derivative functions\n"""\n\n\ndef gradient1(f, v):\n    """Flat gradient of f wrt v."""\n    return pt.flatten(grad(f, v, disconnected_inputs="warn"))\n\n\nempty_gradient = pt.zeros(0, dtype="float32")\n\n\ndef gradient(f, vars=None):\n    if vars is None:\n        vars = cont_inputs(f)\n\n    if vars:\n        return pt.concatenate([gradient1(f, v) for v in vars], axis=0)\n    else:\n        return empty_gradient\n\n\ndef jacobian1(f, v):\n    """Jacobian of f wrt v."""\n    f = pt.flatten(f)\n    idx = pt.arange(f.shape[0], dtype="int32")\n\n    def grad_i(i):\n        return gradient1(f[i], v)\n\n    return pytensor.map(grad_i, idx)[0]\n\n\ndef jacobian(f, vars=None):\n    if vars is None:\n        vars = cont_inputs(f)\n\n    if vars:\n        return pt.concatenate([jacobian1(f, v) for v in vars], axis=1)\n    else:\n        return empty_gradient\n\n\ndef jacobian_diag(f, x):\n    idx = pt.arange(f.shape[0], dtype="int32")\n\n    def grad_ii(i, f, x):\n        return grad(f[i], x)[i]\n\n    return pytensor.scan(\n        grad_ii, sequences=[idx], n_steps=f.shape[0], non_sequences=[f, x], name="jacobian_diag"\n    )[0]\n\n\n@pytensor.config.change_flags(compute_test_value="ignore")\ndef hessian(f, vars=None, negate_output=True):\n    res = jacobian(gradient(f, vars), vars)\n    if negate_output:\n        warnings.warn(\n            "hessian will stop negating the output in a future version of PyMC.\\n"\n            "To suppress this warning set `negate_output=False`",\n            FutureWarning,\n            stacklevel=2,\n        )\n        res = -res\n    return res\n\n\n@pytensor.config.change_flags(compute_test_value="ignore")\ndef hessian_diag1(f, v):\n    g = gradient1(f, v)\n    idx = pt.arange(g.shape[0], dtype="int32")\n\n    def hess_ii(i):\n        return gradient1(g[i], v)[i]\n\n    return pytensor.map(hess_ii, idx)[0]\n\n\n@pytensor.config.change_flags(compute_test_value="ignore")\ndef hessian_diag(f, vars=None, negate_output=True):\n    if vars is None:\n        vars = cont_inputs(f)\n\n    if vars:\n        res = pt.concatenate([hessian_diag1(f, v) for v in vars], axis=0)\n        if negate_output:\n            warnings.warn(\n                "hessian_diag will stop negating the output in a future version of PyMC.\\n"\n                "To suppress this warning set `negate_output=False`",\n                FutureWarning,\n                stacklevel=2,\n            )\n            res = -res\n        return res\n    else:\n        return empty_gradient\n\n\ndef make_shared_replacements(point, vars, model):\n    """\n    Make shared replacements for all *other* variables than the ones passed.\n\n    This way functions can be called many times without setting unchanging variables. Allows us\n    to use func.trust_input by removing the need for DictToArrayBijection and kwargs.\n\n    Parameters\n    ----------\n    point: dictionary mapping variable names to sample values\n    vars: list of variables not to make shared\n    model: model\n\n    Returns\n    -------\n    Dict of variable -> new shared variable\n    """\n    othervars = set(model.value_vars) - set(vars)\n    return {\n        var: pytensor.shared(point[var.name], var.name + "_shared", shape=var.type.shape)\n        for var in othervars\n    }\n\n\ndef join_nonshared_inputs(\n    point: dict[str, np.ndarray],\n    outputs: list[TensorVariable],\n    inputs: list[TensorVariable],\n    shared_inputs: dict[TensorVariable, TensorSharedVariable] | None = None,\n    make_inputs_shared: bool = False,\n) -> tuple[list[TensorVariable], TensorVariable]:\n    """\n    Create new outputs and input TensorVariables where the non-shared inputs are joined in a single raveled vector input.\n\n    Parameters\n    ----------\n    point : dict of {str : array_like}\n        Dictionary that maps each input variable name to a numerical variable. The values\n        are used to extract the shape of each input variable to establish a correct\n        mapping between joined and original inputs. The shape of each variable is\n        assumed to be fixed.\n    outputs : list of TensorVariable\n        List of output TensorVariables whose non-shared inputs will be replaced\n        by a joined vector input.\n    inputs : list of TensorVariable\n        List of input TensorVariables which will be replaced by a joined vector input.\n    shared_inputs : dict of {TensorVariable : TensorSharedVariable}, optional\n        Dict of TensorVariable and their associated TensorSharedVariable in\n        subgraph replacement.\n    make_inputs_shared : bool, default False\n        Whether to make the joined vector input a shared variable.\n\n    Returns\n    -------\n    new_outputs : list of TensorVariable\n        List of new outputs `outputs` TensorVariables that depend on `joined_inputs` and new shared variables as inputs.\n    joined_inputs : TensorVariable\n        Joined input vector TensorVariable for the `new_outputs`\n\n    Examples\n    --------\n    Join the inputs of a simple PyTensor graph.\n\n    .. code-block:: python\n\n        import pytensor.tensor as pt\n        import numpy as np\n\n        from pymc.pytensorf import join_nonshared_inputs\n\n        # Original non-shared inputs\n        x = pt.scalar("x")\n        y = pt.vector("y")\n        # Original output\n        out = x + y\n        print(out.eval({x: np.array(1), y: np.array([1, 2, 3])}))  # [2, 3, 4]\n\n        # New output and inputs\n        [new_out], joined_inputs = join_nonshared_inputs(\n            point={  # Only shapes matter\n                "x": np.zeros(()),\n                "y": np.zeros(3),\n            },\n            outputs=[out],\n            inputs=[x, y],\n        )\n        print(new_out.eval({joined_inputs: np.array([1, 1, 2, 3])}))  # [2, 3, 4]\n\n    Join the input value variables of a model logp.\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            mu_pop = pm.Normal("mu_pop")\n            sigma_pop = pm.HalfNormal("sigma_pop")\n            mu = pm.Normal("mu", mu_pop, sigma_pop, shape=(3,))\n\n            y = pm.Normal("y", mu, 1.0, observed=[0, 1, 2])\n\n        print(\n            model.compile_logp()(\n                {\n                    "mu_pop": 0,\n                    "sigma_pop_log__": 1,\n                    "mu": [0, 1, 2],\n                }\n            )\n        )  # -12.691227342634292\n\n        initial_point = model.initial_point()\n        inputs = model.value_vars\n\n        [logp], joined_inputs = join_nonshared_inputs(\n            point=initial_point,\n            outputs=[model.logp()],\n            inputs=inputs,\n        )\n\n        print(\n            logp.eval(\n                {\n                    joined_inputs: [0, 1, 0, 1, 2],\n                }\n            )\n        )  # -12.691227342634292\n\n    Same as above but with the `mu_pop` value variable being shared.\n\n    .. code-block:: python\n\n        from pytensor import shared\n\n        mu_pop_input, *other_inputs = inputs\n        shared_mu_pop_input = shared(0.0)\n\n        [logp], other_joined_inputs = join_nonshared_inputs(\n            point=initial_point,\n            outputs=[model.logp()],\n            inputs=other_inputs,\n            shared_inputs={mu_pop_input: shared_mu_pop_input},\n        )\n\n        print(\n            logp.eval(\n                {\n                    other_joined_inputs: [1, 0, 1, 2],\n                }\n            )\n        )  # -12.691227342634292\n    """\n    if not inputs:\n        raise ValueError("Empty list of input variables.")\n\n    raveled_inputs = pt.concatenate([var.ravel() for var in inputs])\n\n    if not make_inputs_shared:\n        tensor_type = raveled_inputs.type\n        joined_inputs = tensor_type("joined_inputs")\n    else:\n        joined_values = np.concatenate([point[var.name].ravel() for var in inputs])\n        joined_inputs = pytensor.shared(joined_values, "joined_inputs")\n\n    if pytensor.config.compute_test_value != "off":\n        joined_inputs.tag.test_value = raveled_inputs.tag.test_value\n\n    replace: dict[TensorVariable, TensorVariable] = {}\n    last_idx = 0\n    for var in inputs:\n        shape = point[var.name].shape\n        arr_len = np.prod(shape, dtype=int)\n        replace[var] = joined_inputs[last_idx : last_idx + arr_len].reshape(shape).astype(var.dtype)\n        last_idx += arr_len\n\n    if shared_inputs is not None:\n        replace.update(shared_inputs)\n\n    new_outputs = [\n        pytensor.clone_replace(output, replace, rebuild_strict=False) for output in outputs\n    ]\n    return new_outputs, joined_inputs\n\n\nclass PointFunc:\n    """Wraps so a function so it takes a dict of arguments instead of arguments."""\n\n    __slots__ = ("f",)\n\n    def __init__(self, f):\n        self.f = f\n\n    def __call__(self, state):\n        return self.f(**state)\n\n    def __getattr__(self, item):\n        """Allow access to the original function attributes."""\n        # This is only reached if `__getattribute__` fails.\n        return getattr(self.f, item)\n\n\nclass CallableTensor:\n    """Turns a symbolic variable with one input into a function that returns symbolic arguments with the one variable replaced with the input."""\n\n    def __init__(self, tensor):\n        self.tensor = tensor\n\n    def __call__(self, input):\n        """Replace the single input of symbolic variable to be the passed argument.\n\n        Parameters\n        ----------\n        input: TensorVariable\n        """\n        (oldinput,) = inputvars(self.tensor)\n        return pytensor.clone_replace(self.tensor, {oldinput: input}, rebuild_strict=False)\n\n\ndef ix_(*args):\n    """\n    PyTensor np.ix_ analog.\n\n    See numpy.lib.index_tricks.ix_ for reference\n    """\n    out = []\n    nd = len(args)\n    for k, new in enumerate(args):\n        if new is None:\n            out.append(slice(None))\n        new = pt.as_tensor(new)\n        if new.ndim != 1:\n            raise ValueError("Cross index must be 1 dimensional")\n        new = new.reshape((1,) * k + (new.size,) + (1,) * (nd - k - 1))\n        out.append(new)\n    return tuple(out)\n\n\ndef largest_common_dtype(tensors):\n    dtypes = {\n        str(t.dtype) if hasattr(t, "dtype") else smartfloatX(np.asarray(t)).dtype for t in tensors\n    }\n    return np.stack([np.ones((), dtype=dtype) for dtype in dtypes]).dtype\n\n\ndef find_rng_nodes(\n    variables: Iterable[Variable],\n) -> list[RandomGeneratorSharedVariable]:\n    """Return shared RNG variables in a graph."""\n    return [\n        node for node in graph_inputs(variables) if isinstance(node, RandomGeneratorSharedVariable)\n    ]\n\n\ndef replace_rng_nodes(outputs: Sequence[TensorVariable]) -> list[TensorVariable]:\n    """Replace any RNG nodes upstream of outputs by new RNGs of the same type.\n\n    This can be used when combining a pre-existing graph with a cloned one, to ensure\n    RNGs are unique across the two graphs.\n    """\n    rng_nodes = find_rng_nodes(outputs)\n\n    # Nothing to do here\n    if not rng_nodes:\n        return outputs\n\n    graph = FunctionGraph(outputs=outputs, clone=False)\n    new_rng_nodes = [pytensor.shared(np.random.Generator(np.random.PCG64())) for _ in rng_nodes]\n    graph.replace_all(zip(rng_nodes, new_rng_nodes), import_missing=True)\n    return cast(list[TensorVariable], graph.outputs)\n\n\nSeedSequenceSeed = None | int | Sequence[int] | np.ndarray | np.random.SeedSequence\n\n\ndef reseed_rngs(\n    rngs: Sequence[SharedVariable],\n    seed: SeedSequenceSeed,\n) -> None:\n    """Create a new set of RandomState/Generator for each rng based on a seed."""\n    bit_generators = [\n        np.random.PCG64(sub_seed) for sub_seed in np.random.SeedSequence(seed).spawn(len(rngs))\n    ]\n    for rng, bit_generator in zip(rngs, bit_generators):\n        rng.set_value(np.random.Generator(bit_generator), borrow=True)\n\n\ndef collect_default_updates_inner_fgraph(node: Apply) -> dict[Variable, Variable]:\n    """Collect default updates from node with inner fgraph."""\n    op = node.op\n    inner_updates = collect_default_updates(\n        inputs=op.inner_inputs, outputs=op.inner_outputs, must_be_shared=False\n    )\n\n    # Map inner updates to outer inputs/outputs\n    updates = {}\n    for rng, update in inner_updates.items():\n        inp_idx = op.inner_inputs.index(rng)\n        out_idx = op.inner_outputs.index(update)\n        updates[node.inputs[inp_idx]] = node.outputs[out_idx]\n\n    return updates\n\n\ndef collect_default_updates(\n    outputs: Variable | Sequence[Variable],\n    *,\n    inputs: Sequence[Variable] | None = None,\n    must_be_shared: bool = True,\n) -> dict[Variable, Variable]:\n    """Collect default update expression for shared-variable RNGs used by RVs between inputs and outputs.\n\n    Parameters\n    ----------\n    outputs: list of PyTensor variables\n        List of variables in which graphs default updates will be collected.\n    inputs: list of PyTensor variables, optional\n        Input nodes above which default updates should not be collected.\n        When not provided, search will include top level inputs (roots).\n    must_be_shared: bool, default True\n        Used internally by PyMC. Whether updates should be collected for non-shared\n        RNG input variables. This is used to collect update expressions for inner graphs.\n\n    Examples\n    --------\n    .. code:: python\n\n        import pymc as pm\n        from pytensor.scan import scan\n        from pymc.pytensorf import collect_default_updates\n\n        def scan_step(xtm1):\n            x = xtm1 + pm.Normal.dist()\n            x_update = collect_default_updates([x])\n            return x, x_update\n\n        x0 = pm.Normal.dist()\n\n        xs, updates = scan(\n            fn=scan_step,\n            outputs_info=[x0],\n            n_steps=10,\n        )\n\n        # PyMC makes use of the updates to seed xs properly.\n        # Without updates, it would raise an error.\n        xs_draws = pm.draw(xs, draws=10)\n\n    """\n    # Avoid circular import\n    from pymc.distributions.distribution import SymbolicRandomVariable\n\n    def find_default_update(clients, rng: Variable) -> None | Variable:\n        rng_clients = clients.get(rng, None)\n\n        # Root case, RNG is not used elsewhere\n        if not rng_clients:\n            return None\n\n        if len(rng_clients) > 1:\n            # Multiple clients are techincally fine if they are used in identical operations\n            # We check if the default_update of each client would be the same\n            all_updates = [\n                find_default_update(\n                    # Pass version of clients that includes only one the RNG clients at a time\n                    clients | {rng: [rng_client]},\n                    rng,\n                )\n                for rng_client in rng_clients\n            ]\n            updates = [update for update in all_updates if update is not None]\n            if not updates:\n                return None\n            if len(updates) == 1:\n                return updates[0]\n            else:\n                update, *other_updates = updates\n                if all(\n                    equal_computations([update], [other_update]) for other_update in other_updates\n                ):\n                    return update\n\n                warnings.warn(\n                    f"RNG Variable {rng} has multiple distinct clients {rng_clients}, "\n                    f"likely due to an inconsistent random graph. "\n                    f"No default update will be returned.",\n                    UserWarning,\n                )\n                return None\n\n        [client, _] = rng_clients[0]\n\n        # RNG is an output of the function, this is not a problem\n        if isinstance(client.op, Output):\n            return None\n\n        # RNG is used by another operator, which should output an update for the RNG\n        if isinstance(client.op, RandomVariable):\n            # RandomVariable first output is always the update of the input RNG\n            next_rng = client.outputs[0]\n\n        elif isinstance(client.op, SymbolicRandomVariable):\n            # SymbolicRandomVariable have an explicit method that returns an\n            # update mapping for their RNG(s)\n            next_rng = client.op.update(client).get(rng)\n            if next_rng is None:\n                raise ValueError(\n                    f"No update found for at least one RNG used in SymbolicRandomVariable Op {client.op}"\n                )\n        elif isinstance(client.op, Scan):\n            # Check if any shared output corresponds to the RNG\n            rng_idx = client.inputs.index(rng)\n            io_map = client.op.get_oinp_iinp_iout_oout_mappings()["outer_out_from_outer_inp"]\n            out_idx = io_map.get(rng_idx, -1)\n            if out_idx != -1:\n                next_rng = client.outputs[out_idx]\n            else:  # No break\n                raise ValueError(\n                    f"No update found for at least one RNG used in Scan Op {client.op}.\\n"\n                    "You can use `pytensorf.collect_default_updates` inside the Scan function to return updates automatically."\n                )\n        elif isinstance(client.op, OpFromGraph):\n            try:\n                next_rng = collect_default_updates_inner_fgraph(client).get(rng)\n                if next_rng is None:\n                    # OFG either does not make use of this RNG or inconsistent use that will have emitted a warning\n                    return None\n            except ValueError as exc:\n                raise ValueError(\n                    f"No update found for at least one RNG used in OpFromGraph Op {client.op}.\\n"\n                    "You can use `pytensorf.collect_default_updates` and include those updates as outputs."\n                ) from exc\n        else:\n            # We don\'t know how this RNG should be updated. The user should provide an update manually\n            return None\n\n        # Recurse until we find final update for RNG\n        nested_next_rng = find_default_update(clients, next_rng)\n        if nested_next_rng is None:\n            # There were no more uses of this next_rng\n            return next_rng\n        else:\n            return nested_next_rng\n\n    if inputs is None:\n        inputs = []\n\n    outs = makeiter(outputs)\n    fg = FunctionGraph(outputs=outs, clone=False)\n    clients = fg.clients\n\n    rng_updates = {}\n    # Iterate over input RNGs. Only consider shared RNGs if `must_be_shared==True`\n    for input_rng in (\n        inp\n        for inp in graph_inputs(outs, blockers=inputs)\n        if (\n            (not must_be_shared or isinstance(inp, SharedVariable))\n            and isinstance(inp.type, RandomType)\n        )\n    ):\n        # Even if an explicit default update is provided, we call it to\n        # issue any warnings about invalid random graphs.\n        default_update = find_default_update(clients, input_rng)\n\n        # Respect default update if provided\n        if hasattr(input_rng, "default_update") and input_rng.default_update is not None:\n            rng_updates[input_rng] = input_rng.default_update\n        else:\n            if default_update is not None:\n                rng_updates[input_rng] = default_update\n\n    return rng_updates\n\n\ndef compile(\n    inputs,\n    outputs,\n    random_seed: SeedSequenceSeed = None,\n    mode=None,\n    **kwargs,\n) -> Function:\n    """Use ``pytensor.function`` with specialized pymc rewrites always enabled.\n\n    This function also ensures shared Generator used by RandomVariables\n    in the graph are updated across calls, to ensure independent draws.\n\n    Parameters\n    ----------\n    inputs: list of TensorVariables, optional\n        Inputs of the compiled PyTensor function\n    outputs: list of TensorVariables, optional\n        Outputs of the compiled PyTensor function\n    random_seed: int, array-like of int or SeedSequence, optional\n        Seed used to override any RandomState/Generator shared variables in the graph.\n        If not specified, the value of original shared variables will still be overwritten.\n    mode: optional\n        PyTensor mode used to compile the function\n\n    Included rewrites\n    -----------------\n    random_make_inplace\n        Ensures that compiled functions containing random variables will produce new\n        samples on each call.\n    local_check_parameter_to_ninf_switch\n        Replaces CheckParameterValue assertions is logp expressions with Switches\n        that return -inf in place of the assert.\n\n    Optional rewrites\n    -----------------\n    local_remove_check_parameter\n        Replaces CheckParameterValue assertions is logp expressions. This is used\n        as an alteranative to the default local_check_parameter_to_ninf_switch whenenver\n        this function is called within a model context and the model `check_bounds` flag\n        is set to False.\n    """\n    # Create an update mapping of RandomVariable\'s RNG so that it is automatically\n    # updated after every function call\n    rng_updates = collect_default_updates(\n        inputs=[inp.variable if isinstance(inp, pytensor.In) else inp for inp in inputs],\n        outputs=[\n            out.variable if isinstance(out, pytensor.Out) else out for out in makeiter(outputs)\n        ],\n    )\n\n    # We always reseed random variables as this provides RNGs with no chances of collision\n    if rng_updates:\n        rngs = cast(list[SharedVariable], list(rng_updates))\n        reseed_rngs(rngs, random_seed)\n\n    # If called inside a model context, see if check_bounds flag is set to False\n    try:\n        from pymc.model import modelcontext\n\n        model = modelcontext(None)\n        check_bounds = model.check_bounds\n    except TypeError:\n        check_bounds = True\n    check_parameter_opt = (\n        "local_check_parameter_to_ninf_switch" if check_bounds else "local_remove_check_parameter"\n    )\n\n    mode = get_mode(mode)\n    opt_qry = mode.provided_optimizer.including("random_make_inplace", check_parameter_opt)\n    mode = Mode(linker=mode.linker, optimizer=opt_qry)\n    pytensor_function = pytensor.function(\n        inputs,\n        outputs,\n        updates={**rng_updates, **kwargs.pop("updates", {})},\n        mode=mode,\n        **kwargs,\n    )\n    return pytensor_function\n\n\ndef constant_fold(\n    xs: Sequence[TensorVariable], raise_not_constant: bool = True\n) -> tuple[np.ndarray | Variable, ...]:\n    """Use constant folding to get constant values of a graph.\n\n    Parameters\n    ----------\n    xs: Sequence of TensorVariable\n        The variables that are to be constant folded\n    raise_not_constant: bool, default True\n        Raises NotConstantValueError if any of the variables cannot be constant folded.\n        This should only be disabled with care, as the graphs are cloned before\n        attempting constant folding, and any old non-shared inputs will not work with\n        the returned outputs\n    """\n    fg = FunctionGraph(outputs=xs, features=[ShapeFeature()], copy_inputs=False, clone=True)\n\n    # The default rewrite_graph includes a constant_folding that is not always applied.\n    # We use an unconditional constant_folding as the last pass to ensure a thorough constant folding.\n    rewrite_graph(fg)\n    topo_unconditional_constant_folding.apply(fg)\n\n    folded_xs = fg.outputs\n\n    if raise_not_constant and not all(isinstance(folded_x, Constant) for folded_x in folded_xs):\n        raise NotConstantValueError\n\n    return tuple(\n        folded_x.data if isinstance(folded_x, Constant) else folded_x for folded_x in folded_xs\n    )\n\n\ndef rewrite_pregrad(graph):\n    """Apply simplifying or stabilizing rewrites to graph that are safe to use pre-grad."""\n    return rewrite_graph(graph, include=("canonicalize", "stabilize"))\n\n\nclass StringType(Type[str]):\n    def clone(self, **kwargs):\n        return type(self)()\n\n    def filter(self, x, strict=False, allow_downcast=None):\n        if isinstance(x, str):\n            return x\n        else:\n            raise TypeError("Expected a string!")\n\n    def __str__(self):\n        return "string"\n\n    @staticmethod\n    def may_share_memory(a, b):\n        return isinstance(a, str) and a is b\n\n\nstringtype = StringType()\n\n\nclass StringConstant(Constant):\n    pass\n\n\n@pytensor._as_symbolic.register(str)\ndef as_symbolic_string(x, **kwargs):\n    return StringConstant(stringtype, x)\n\n\ndef toposort_replace(\n    fgraph: FunctionGraph, replacements: Sequence[tuple[Variable, Variable]], reverse: bool = False\n) -> None:\n    """Replace multiple variables in place in topological order."""\n    fgraph_toposort = {node: i for i, node in enumerate(fgraph.toposort())}\n    _inner_fgraph_toposorts = {}  # Cache inner toposorts\n\n    def _nested_toposort_index(var, fgraph_toposort) -> tuple[int]:\n        """Compute position of variable in fgraph toposort.\n\n        When a variable is an OpFromGraph output, extend output with the toposort index of the inner graph(s).\n\n        This allows ordering variables that come from the same OpFromGraph.\n        """\n        if not var.owner:\n            return (-1,)\n\n        index = fgraph_toposort[var.owner]\n\n        # Recurse into OpFromGraphs\n        # TODO: Could also recurse into Scans\n        if isinstance(var.owner.op, OpFromGraph):\n            inner_fgraph = var.owner.op.fgraph\n\n            if inner_fgraph not in _inner_fgraph_toposorts:\n                _inner_fgraph_toposorts[inner_fgraph] = {\n                    node: i for i, node in enumerate(inner_fgraph.toposort())\n                }\n\n            inner_fgraph_toposort = _inner_fgraph_toposorts[inner_fgraph]\n            inner_var = inner_fgraph.outputs[var.owner.outputs.index(var)]\n            return (index, *_nested_toposort_index(inner_var, inner_fgraph_toposort))\n        else:\n            return (index,)\n\n    sorted_replacements = sorted(\n        replacements,\n        key=lambda pair: _nested_toposort_index(pair[0], fgraph_toposort),\n        reverse=reverse,\n    )\n    fgraph.replace_all(sorted_replacements, import_missing=True)\n\n\ndef normalize_rng_param(rng: None | Variable) -> Variable:\n    """Validate rng is a valid type or create a new one if None."""\n    if rng is None:\n        rng = pytensor.shared(np.random.default_rng())\n    elif not isinstance(rng.type, RandomType):\n        raise TypeError(\n            "The type of rng should be an instance of either RandomGeneratorType or RandomStateType"\n        )\n    return rng\n',
            'tests/test_pytensorf.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport numpy as np\nimport numpy.ma as ma\nimport numpy.testing as npt\nimport pandas as pd\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\nimport scipy.sparse as sps\n\nfrom pytensor import scan, shared\nfrom pytensor.compile import UnusedInputError\nfrom pytensor.compile.builders import OpFromGraph\nfrom pytensor.graph.basic import Variable, equal_computations\nfrom pytensor.tensor.subtensor import AdvancedIncSubtensor\n\nimport pymc as pm\n\nfrom pymc.data import Minibatch, MinibatchOp\nfrom pymc.distributions.dist_math import check_parameters\nfrom pymc.distributions.distribution import SymbolicRandomVariable\nfrom pymc.exceptions import NotConstantValueError\nfrom pymc.logprob.utils import ParameterValueError\nfrom pymc.pytensorf import (\n    PointFunc,\n    collect_default_updates,\n    compile,\n    constant_fold,\n    convert_data,\n    extract_obs_data,\n    hessian,\n    hessian_diag,\n    replace_rng_nodes,\n    replace_vars_in_graphs,\n    reseed_rngs,\n)\nfrom pymc.vartypes import int_types\n\n\n@pytest.mark.parametrize(\n    argnames="np_array",\n    argvalues=[\n        np.array([[1.0], [2.0], [-1.0]]),\n        np.array([[1.0, 1.0, 1.0], [0.0, 0.0, 0.0]]),\n        np.ones(shape=(10, 1)),\n    ],\n)\ndef test_pd_dataframe_as_tensor_variable(np_array: np.ndarray) -> None:\n    df = pd.DataFrame(np_array)\n    np.testing.assert_array_equal(pt.as_tensor_variable(df).eval(), np_array)\n\n\n@pytest.mark.parametrize(\n    argnames="np_array",\n    argvalues=[np.array([1.0, 2.0, -1.0]), np.ones(shape=4), np.zeros(shape=10), [1, 2, 3, 4]],\n)\ndef test_pd_series_as_tensor_variable(np_array: np.ndarray) -> None:\n    df = pd.Series(np_array)\n    np.testing.assert_array_equal(pt.as_tensor_variable(df).eval(), np_array)\n\n\ndef test_pd_as_tensor_variable_multiindex() -> None:\n    tuples = [("L", "Q"), ("L", "I"), ("O", "L"), ("O", "I")]\n\n    index = pd.MultiIndex.from_tuples(tuples, names=["Id1", "Id2"])\n\n    df = pd.DataFrame({"A": [12.0, 80.0, 30.0, 20.0], "B": [120.0, 700.0, 30.0, 20.0]}, index=index)\n    np_array = np.array([[12.0, 80.0, 30.0, 20.0], [120.0, 700.0, 30.0, 20.0]]).T\n    assert isinstance(df.index, pd.MultiIndex)\n    np.testing.assert_array_equal(pt.as_tensor_variable(df).eval(), np_array)\n\n\nclass TestBroadcasting:\n    def test_make_shared_replacements(self):\n        """Check if pm.make_shared_replacements preserves broadcasting."""\n\n        with pm.Model() as test_model:\n            test1 = pm.Normal("test1", mu=0.0, sigma=1.0, size=(1, 10))\n            test2 = pm.Normal("test2", mu=0.0, sigma=1.0, size=(10, 1))\n\n        # Replace test1 with a shared variable, keep test 2 the same\n        replacement = pm.make_shared_replacements(\n            test_model.initial_point(), [test_model.test2], test_model\n        )\n        assert (\n            test_model.test1.broadcastable\n            == replacement[test_model.rvs_to_values[test_model.test1]].broadcastable\n        )\n\n    def test_metropolis_sampling(self):\n        """Check if the Metropolis sampler can handle broadcasting."""\n        with pm.Model() as test_model:\n            test1 = pm.Normal("test1", mu=0.0, sigma=1.0, size=(1, 10))\n            test2 = pm.Normal("test2", mu=test1, sigma=1.0, size=(10, 10))\n\n            step = pm.Metropolis()\n            # TODO FIXME: Assert whatever it is we\'re testing\n            pm.sample(tune=5, draws=7, cores=1, step=step, compute_convergence_checks=False)\n\n\ndef _make_along_axis_idx(arr_shape, indices, axis):\n    # compute dimensions to iterate over\n    if str(indices.dtype) not in int_types:\n        raise IndexError("`indices` must be an integer array")\n    shape_ones = (1,) * indices.ndim\n    dest_dims = [*list(range(axis)), None, *list(range(axis + 1, indices.ndim))]\n\n    # build a fancy index, consisting of orthogonal aranges, with the\n    # requested index inserted at the right location\n    fancy_index = []\n    for dim, n in zip(dest_dims, arr_shape):\n        if dim is None:\n            fancy_index.append(indices)\n        else:\n            ind_shape = shape_ones[:dim] + (-1,) + shape_ones[dim + 1 :]\n            fancy_index.append(np.arange(n).reshape(ind_shape))\n\n    return tuple(fancy_index)\n\n\nclass TestExtractObsData:\n    def test_root_variable(self):\n        with pytest.raises(TypeError):\n            extract_obs_data(pt.matrix())\n\n    def test_constant_variable(self):\n        data = np.random.normal(size=(2, 3))\n        data_pt = pt.as_tensor(data)\n        res = extract_obs_data(data_pt)\n\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, data)\n\n    def test_shared_variable(self):\n        data = np.random.normal(size=(2, 3))\n        data_pt = shared(data)\n\n        res = extract_obs_data(data_pt)\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, data)\n\n    def test_masked_variable(self):\n        # Extract data from auto-imputation graph\n        data = np.random.normal(size=(2, 3))\n        data_pt = pt.as_tensor(data)\n        mask = np.random.binomial(1, 0.5, size=(2, 3)).astype(bool)\n\n        # AdvancedIncSubtensor check\n        data_m = np.ma.MaskedArray(data, mask)\n        missing_values = data_pt.type()[mask]\n        constant = pt.as_tensor(data_m.filled())\n        z_at = pt.set_subtensor(constant[mask.nonzero()], missing_values)\n        assert isinstance(z_at.owner.op, AdvancedIncSubtensor)\n\n        res = extract_obs_data(z_at)\n        assert isinstance(res, np.ndarray)\n        assert np.ma.allequal(res, data_m)\n\n    def test_cast_variable(self):\n        # Cast check\n        data = np.array(5)\n        data_pt = pt.cast(pt.as_tensor(5.0), np.int64)\n\n        res = extract_obs_data(data_pt)\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, data)\n\n    def test_minibatch_variable(self):\n        x = np.arange(5)\n        y = x * 2\n\n        x_mb, y_mb = Minibatch(x, y, batch_size=2)\n        assert isinstance(x_mb.owner.op, MinibatchOp)\n        assert isinstance(y_mb.owner.op, MinibatchOp)\n\n        res = extract_obs_data(x_mb)\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, x)\n\n        res = extract_obs_data(y_mb)\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, y)\n\n    def test_pytensor_operations(self):\n        x = np.array([1, 2, 3])\n        target = 1 + 3 * pt.as_tensor_variable(x)\n\n        res = extract_obs_data(target)\n        assert isinstance(res, np.ndarray)\n        np.testing.assert_array_equal(res, np.array([4, 7, 10]))\n\n    def test_pytensor_operations_raises(self):\n        x = pt.scalar("x")\n        target = 1 + 3 * x\n\n        with pytest.raises(TypeError, match="Data cannot be extracted from"):\n            extract_obs_data(target)\n\n\n@pytest.mark.parametrize("input_dtype", ["int32", "int64", "float32", "float64"])\ndef test_convert_data(input_dtype):\n    """\n    Ensure that convert_data returns the dense array, masked array,\n    graph variable, TensorVariable, or sparse matrix as appropriate.\n    """\n    # Create the various inputs to the function\n    sparse_input = sps.csr_matrix(np.eye(3)).astype(input_dtype)\n    dense_input = np.arange(9).reshape((3, 3)).astype(input_dtype)\n\n    input_name = "input_variable"\n    pytensor_graph_input = pt.as_tensor(dense_input, name=input_name)\n    pandas_input = pd.DataFrame(dense_input)\n\n    # All the even numbers are replaced with NaN\n    missing_numpy_input = np.array([[np.nan, 1, np.nan], [3, np.nan, 5], [np.nan, 7, np.nan]])\n    missing_pandas_input = pd.DataFrame(missing_numpy_input)\n    masked_array_input = ma.array(dense_input, mask=(np.mod(dense_input, 2) == 0))\n\n    # Alias the function to be tested\n    func = convert_data\n\n    #####\n    # Perform the various tests\n    #####\n    # Check function behavior with dense arrays and pandas dataframes\n    # without missing values\n    for input_value in [dense_input, pandas_input]:\n        func_output = func(input_value)\n        assert isinstance(func_output, np.ndarray)\n        assert func_output.shape == input_value.shape\n        npt.assert_allclose(func_output, dense_input)\n\n    # Check function behavior with sparse matrix inputs\n    sparse_output = func(sparse_input)\n    assert sps.issparse(sparse_output)\n    assert sparse_output.shape == sparse_input.shape\n    npt.assert_allclose(sparse_output.toarray(), sparse_input.toarray())\n\n    # Check function behavior when using masked array inputs and pandas\n    # objects with missing data\n    for input_value in [missing_numpy_input, masked_array_input, missing_pandas_input]:\n        func_output = func(input_value)\n        assert isinstance(func_output, ma.core.MaskedArray)\n        assert func_output.shape == input_value.shape\n        npt.assert_allclose(func_output, masked_array_input)\n\n    # Check function behavior with PyTensor graph variable\n    pytensor_output = func(pytensor_graph_input)\n    assert isinstance(pytensor_output, Variable)\n    npt.assert_allclose(pytensor_output.eval(), pytensor_graph_input.eval())\n    intX = pm.pytensorf._conversion_map[pytensor.config.floatX]\n    if dense_input.dtype == intX or dense_input.dtype == pytensor.config.floatX:\n        assert pytensor_output.owner is None  # func should not have added new nodes\n        assert pytensor_output.name == input_name\n    else:\n        assert pytensor_output.owner is not None  # func should have casted\n        assert pytensor_output.owner.inputs[0].name == input_name\n\n    if "float" in input_dtype:\n        assert pytensor_output.dtype == pytensor.config.floatX\n    else:\n        assert pytensor_output.dtype == intX\n\n\ndef test_pandas_to_array_pandas_index():\n    data = pd.Index([1, 2, 3])\n    result = convert_data(data)\n    expected = np.array([1, 2, 3])\n    np.testing.assert_array_equal(result, expected)\n\n\nclass TestCompile:\n    def test_check_bounds_flag(self):\n        """Test that CheckParameterValue Ops are replaced or removed when using compile_pymc"""\n        logp = pt.ones(3)\n        cond = np.array([1, 0, 1])\n        bound = check_parameters(logp, cond)\n\n        with pm.Model() as m:\n            pass\n\n        with pytest.raises(ParameterValueError):\n            pytensor.function([], bound)()\n\n        m.check_bounds = False\n        with m:\n            assert np.all(compile([], bound)() == 1)\n\n        m.check_bounds = True\n        with m:\n            assert np.all(compile([], bound)() == -np.inf)\n\n    def test_check_parameters_can_be_replaced_by_ninf(self):\n        expr = pt.vector("expr", shape=(3,))\n        cond = pt.ge(expr, 0)\n\n        final_expr = check_parameters(expr, cond, can_be_replaced_by_ninf=True)\n        fn = compile([expr], final_expr)\n        np.testing.assert_array_equal(fn(expr=[1, 2, 3]), [1, 2, 3])\n        np.testing.assert_array_equal(fn(expr=[-1, 2, 3]), [-np.inf, -np.inf, -np.inf])\n\n        final_expr = check_parameters(expr, cond, msg="test", can_be_replaced_by_ninf=False)\n        fn = compile([expr], final_expr)\n        np.testing.assert_array_equal(fn(expr=[1, 2, 3]), [1, 2, 3])\n        with pytest.raises(ParameterValueError, match="test"):\n            fn([-1, 2, 3])\n\n    def test_compile_pymc_sets_rng_updates(self):\n        rng = pytensor.shared(np.random.default_rng(0))\n        x = pm.Normal.dist(rng=rng)\n        assert x.owner.inputs[0] is rng\n        f = compile([], x)\n        assert not np.isclose(f(), f())\n\n        # Check that update was not done inplace\n        assert rng.default_update is None\n        f = pytensor.function([], x)\n        assert f() == f()\n\n    def test_compile_pymc_with_updates(self):\n        x = pytensor.shared(0)\n        f = compile([], x, updates={x: x + 1})\n        assert f() == 0\n        assert f() == 1\n\n    def test_compile_pymc_missing_default_explicit_updates(self):\n        rng = pytensor.shared(np.random.default_rng(0))\n        x = pm.Normal.dist(rng=rng)\n\n        # By default, compile_pymc should update the rng of x\n        f = compile([], x)\n        assert f() != f()\n\n        # An explicit update should override the default_update, like pytensor.function does\n        # For testing purposes, we use an update that leaves the rng unchanged\n        f = compile([], x, updates={rng: rng})\n        assert f() == f()\n\n        # If we specify a custom default_update directly it should use that instead.\n        rng.default_update = rng\n        f = compile([], x)\n        assert f() == f()\n\n        # And again, it should be overridden by an explicit update\n        f = compile([], x, updates={rng: x.owner.outputs[0]})\n        assert f() != f()\n\n    def test_compile_pymc_updates_inputs(self):\n        """Test that compile_pymc does not include rngs updates of variables that are inputs\n        or ancestors to inputs\n        """\n        x = pt.random.normal()\n        y = pt.random.normal(x)\n        z = pt.random.normal(y)\n\n        for inputs, rvs_in_graph in (\n            ([], 3),\n            ([x], 2),\n            ([y], 1),\n            ([z], 0),\n            ([x, y], 1),\n            ([x, y, z], 0),\n        ):\n            fn = compile(inputs, z, on_unused_input="ignore")\n            fn_fgraph = fn.maker.fgraph\n            # Each RV adds a shared input for its rng\n            assert len(fn_fgraph.inputs) == len(inputs) + rvs_in_graph\n            # If the output is an input, the graph has a DeepCopyOp\n            assert len(fn_fgraph.apply_nodes) == max(rvs_in_graph, 1)\n            # Each RV adds a shared output for its rng\n            assert len(fn_fgraph.outputs) == 1 + rvs_in_graph\n\n    def test_compile_pymc_symbolic_rv_missing_update(self):\n        """Test that error is raised if SymbolicRandomVariable Op does not\n        provide rule for updating RNG"""\n\n        class SymbolicRV(OpFromGraph):\n            def update(self, node):\n                # Update is provided for rng1 but not rng2\n                return {node.inputs[0]: node.outputs[0]}\n\n        SymbolicRandomVariable.register(SymbolicRV)\n\n        # No problems at first, as the one RNG is given the update rule\n        rng1 = pytensor.shared(np.random.default_rng())\n        dummy_rng1 = rng1.type()\n        dummy_next_rng1, dummy_x1 = SymbolicRV(\n            [dummy_rng1],\n            pt.random.normal(rng=dummy_rng1).owner.outputs,\n        )(rng1)\n        fn = compile(inputs=[], outputs=dummy_x1, random_seed=433)\n        assert fn() != fn()\n\n        # Now there\'s a problem as there is no update rule for rng2\n        rng2 = pytensor.shared(np.random.default_rng())\n        dummy_rng2 = rng2.type()\n        dummy_next_rng1, dummy_x1, dummy_next_rng2, dummy_x2 = SymbolicRV(\n            [dummy_rng1, dummy_rng2],\n            [\n                *pt.random.normal(rng=dummy_rng1).owner.outputs,\n                *pt.random.normal(rng=dummy_rng2).owner.outputs,\n            ],\n        )(rng1, rng2)\n        with pytest.raises(\n            ValueError, match="No update found for at least one RNG used in SymbolicRandomVariable"\n        ):\n            compile(inputs=[], outputs=[dummy_x1, dummy_x2])\n\n    def test_random_seed(self):\n        seedx = pytensor.shared(np.random.default_rng(1))\n        seedy = pytensor.shared(np.random.default_rng(1))\n        x = pt.random.normal(rng=seedx)\n        y = pt.random.normal(rng=seedy)\n\n        # Shared variables are the same, so outputs will be identical\n        f0 = pytensor.function([], [x, y])\n        x0_eval, y0_eval = f0()\n        assert x0_eval == y0_eval\n\n        # The variables will be reseeded with new seeds by default\n        f1 = compile([], [x, y])\n        x1_eval, y1_eval = f1()\n        assert x1_eval != y1_eval\n\n        # Check that seeding works\n        f2 = compile([], [x, y], random_seed=1)\n        x2_eval, y2_eval = f2()\n        assert x2_eval != x1_eval\n        assert y2_eval != y1_eval\n\n        f3 = compile([], [x, y], random_seed=1)\n        x3_eval, y3_eval = f3()\n        assert x3_eval == x2_eval\n        assert y3_eval == y2_eval\n\n    @pytest.mark.filterwarnings("error")  # This is part of the test\n    def test_multiple_updates_same_variable(self):\n        rng = pytensor.shared(np.random.default_rng(), name="rng")\n        x = pt.random.normal(0, rng=rng)\n        y = pt.random.normal(1, rng=rng)\n\n        # No warnings if only one variable is used\n        assert compile([], [x])\n        assert compile([], [y])\n\n        user_warn_msg = "RNG Variable rng has multiple distinct clients"\n        with pytest.warns(UserWarning, match=user_warn_msg):\n            f = compile([], [x, y], random_seed=456)\n        assert f() == f()\n\n        # The user can provide an explicit update, but we will still issue a warning\n        with pytest.warns(UserWarning, match=user_warn_msg):\n            f = compile([], [x, y], updates={rng: y.owner.outputs[0]}, random_seed=456)\n        assert f() != f()\n\n        # Same with default update\n        rng.default_update = x.owner.outputs[0]\n        with pytest.warns(UserWarning, match=user_warn_msg):\n            f = compile([], [x, y], updates={rng: y.owner.outputs[0]}, random_seed=456)\n        assert f() != f()\n\n    @pytest.mark.filterwarnings("error")  # This is part of the test\n    def test_duplicated_client_nodes(self):\n        """Test compile_pymc can handle duplicated (mergeable) RV updates."""\n        rng = pytensor.shared(np.random.default_rng(1))\n        x = pt.random.normal(rng=rng)\n        y = x.owner.clone().default_output()\n\n        fn = compile([], [x, y], random_seed=1)\n        res_x1, res_y1 = fn()\n        assert res_x1 == res_y1\n        res_x2, res_y2 = fn()\n        assert res_x2 == res_y2\n        assert res_x1 != res_x2\n\n    def test_nested_updates(self):\n        rng = pytensor.shared(np.random.default_rng())\n        next_rng1, x = pt.random.normal(rng=rng).owner.outputs\n        next_rng2, y = pt.random.normal(rng=next_rng1).owner.outputs\n        next_rng3, z = pt.random.normal(rng=next_rng2).owner.outputs\n\n        collect_default_updates(inputs=[], outputs=[x, y, z]) == {rng: next_rng3}\n\n        fn = compile([], [x, y, z], random_seed=514)\n        assert not set(np.array(fn())) & set(np.array(fn()))\n\n        # A local myopic rule (as PyMC used before, would not work properly)\n        fn = pytensor.function([], [x, y, z], updates={rng: next_rng1})\n        assert set(np.array(fn())) & set(np.array(fn()))\n\n    def test_collect_default_updates_must_be_shared(self):\n        shared_rng = pytensor.shared(np.random.default_rng())\n        nonshared_rng = shared_rng.type()\n\n        next_rng_of_shared, x = pt.random.normal(rng=shared_rng).owner.outputs\n        next_rng_of_nonshared, y = pt.random.normal(rng=nonshared_rng).owner.outputs\n\n        res = collect_default_updates(inputs=[nonshared_rng], outputs=[x, y])\n        assert res == {shared_rng: next_rng_of_shared}\n\n        res = collect_default_updates(inputs=[nonshared_rng], outputs=[x, y], must_be_shared=False)\n        assert res == {shared_rng: next_rng_of_shared, nonshared_rng: next_rng_of_nonshared}\n\n    def test_scan_updates(self):\n        def step_with_update(x, rng):\n            next_rng, x = pm.Normal.dist(x, rng=rng).owner.outputs\n            return x, {rng: next_rng}\n\n        def step_wo_update(x, rng):\n            return step_with_update(x, rng)[0]\n\n        rng = pytensor.shared(np.random.default_rng())\n\n        xs, next_rng = scan(\n            fn=step_wo_update,\n            outputs_info=[pt.zeros(())],\n            non_sequences=[rng],\n            n_steps=10,\n            name="test_scan",\n        )\n\n        assert not next_rng\n\n        with pytest.raises(\n            ValueError,\n            match="No update found for at least one RNG used in Scan Op",\n        ):\n            collect_default_updates([xs])\n\n        ys, next_rng = scan(\n            fn=step_with_update,\n            outputs_info=[pt.zeros(())],\n            non_sequences=[rng],\n            n_steps=10,\n        )\n\n        assert collect_default_updates([ys]) == {rng: next(iter(next_rng.values()))}\n\n        fn = compile([], ys, random_seed=1)\n        assert not (set(fn()) & set(fn()))\n\n    def test_op_from_graph_updates(self):\n        rng = pytensor.shared(np.random.default_rng())\n        next_rng_, x_ = pt.random.normal(size=(10,), rng=rng).owner.outputs\n\n        x = OpFromGraph([], [x_])()\n        with pytest.raises(\n            ValueError,\n            match="No update found for at least one RNG used in OpFromGraph Op",\n        ):\n            collect_default_updates([x])\n\n        next_rng, x = OpFromGraph([], [next_rng_, x_])()\n        assert collect_default_updates([x]) == {rng: next_rng}\n        fn = compile([], x, random_seed=1)\n        assert not (set(fn()) & set(fn()))\n\n    def test_unused_ofg_rng(self):\n        rng = pytensor.shared(np.random.default_rng())\n        next_rng, x = pt.random.normal(rng=rng).owner.outputs\n        ofg1 = OpFromGraph([rng], [next_rng, x])\n        ofg2 = OpFromGraph([rng, x], [x + 1])\n\n        next_rng, x = ofg1(rng)\n        y = ofg2(rng, x)\n\n        # In all these cases the update should be the same\n        assert collect_default_updates([x]) == {rng: next_rng}\n        assert collect_default_updates([y]) == {rng: next_rng}\n        assert collect_default_updates([x, y]) == {rng: next_rng}\n\n\ndef test_replace_rng_nodes():\n    rng = pytensor.shared(np.random.default_rng())\n    x = pt.random.normal(rng=rng)\n    x_rng, *x_non_rng_inputs = x.owner.inputs\n\n    cloned_x = x.owner.clone().default_output()\n    cloned_x_rng, *cloned_x_non_rng_inputs = cloned_x.owner.inputs\n\n    # RNG inputs are the same across the two variables\n    assert x_rng is cloned_x_rng\n\n    (new_x,) = replace_rng_nodes([cloned_x])\n    new_x_rng, *new_x_non_rng_inputs = new_x.owner.inputs\n\n    # Variables are still the same\n    assert new_x is cloned_x\n\n    # RNG inputs are not the same as before\n    assert new_x_rng is not x_rng\n\n    # All other inputs are the same as before\n    for non_rng_inputs, new_non_rng_inputs in zip(x_non_rng_inputs, new_x_non_rng_inputs):\n        assert non_rng_inputs is new_non_rng_inputs\n\n\ndef test_reseed_rngs():\n    # Reseed_rngs uses the `PCG64` bit_generator, which is currently the default\n    # bit_generator used by NumPy. If this default changes in the future, this test will\n    # catch that. We will then have to decide whether to switch to the new default in\n    # PyMC or whether to stick with the older one (PCG64). This will pose a trade-off\n    # between backwards reproducibility and better/faster seeding. If we decide to change,\n    # the next line should be updated:\n    default_rng = np.random.PCG64\n    assert isinstance(np.random.default_rng().bit_generator, default_rng)\n\n    seed = 543\n\n    bit_generators = [default_rng(sub_seed) for sub_seed in np.random.SeedSequence(seed).spawn(2)]\n\n    rngs = [pytensor.shared(np.random.Generator(default_rng())) for _ in range(2)]\n    for rng, bit_generator in zip(rngs, bit_generators):\n        assert rng.get_value().bit_generator.state != bit_generator.state\n\n    reseed_rngs(rngs, seed)\n    for rng, bit_generator in zip(rngs, bit_generators):\n        assert rng.get_value().bit_generator.state == bit_generator.state\n\n\nclass TestConstantFold:\n    def test_constant_fold(self):\n        x = pt.random.normal(size=(5,))\n        y = pt.arange(x.size)\n\n        res = constant_fold((y, y.shape))\n        assert np.array_equal(res[0], np.arange(5))\n        assert tuple(res[1]) == (5,)\n\n    def test_constant_fold_raises(self):\n        size = pytensor.shared(5)\n        x = pt.random.normal(size=(size,))\n        y = pt.arange(x.size)\n\n        with pytest.raises(NotConstantValueError):\n            constant_fold((y, y.shape))\n\n        res = constant_fold((y, y.shape), raise_not_constant=False)\n        assert tuple(res[1].eval()) == (5,)\n\n    def test_inputs_preserved(self):\n        # Make sure constant_folded graph depends on original graph inputs (not copies)\n        # Regression test for #7387\n        a = pt.scalar("a", dtype="int")\n        out = pt.empty((a,))\n        (out_shape,) = constant_fold((out.shape[0],), raise_not_constant=False)\n        assert out_shape is a\n\n    def test_constant_fold_alloc(self):\n        # By default, Alloc outputs cannot be constant folded\n        x = pt.alloc(pt.arange(5), 2, 5)\n        np.testing.assert_allclose(constant_fold([x])[0], np.broadcast_to(np.arange(5), (2, 5)))\n\n\ndef test_replace_vars_in_graphs():\n    inp = shared(0.0, name="inp")\n    x = pm.Normal.dist(inp)\n\n    replacements = {inp: inp + 100}\n    [new_x] = replace_vars_in_graphs([x], replacements=replacements)\n\n    assert x.eval() < 50\n    assert new_x.eval() > 50\n\n\ndef test_replace_vars_in_graphs_nested_reference():\n    # Replace both `x` and `y`, where the replacement of y references `x`\n    x = pm.HalfNormal.dist(1e-3, name="x")\n    neg_x = -x\n    y = pm.Uniform.dist(neg_x, x, name="y")\n    x_value = x.clone()\n    y_value = y.clone()\n    replacements = {x: x_value, y: neg_x + y_value}\n    [new_x, new_y] = replace_vars_in_graphs([x, y], replacements=replacements)\n    assert new_x.eval({x_value: 100}) == 100\n    assert new_y.eval({x_value: 100, y_value: 1}) == -99\n    assert new_y.eval({neg_x: 100, y_value: 1}) == 101\n    assert np.abs(x.eval()) < 1\n    # Confirm the original `y` variable is changed in place\n    # This is unavoidable if we want to respect the identity of the replacement variables\n    # As when imputing `neg_x` and `x` while evaluating `new_y` above and below.\n    # This assertion could fail with probability 1/10000\n    assert np.abs(y.eval({x_value: 10000})) > 1\n\n    # Only replace `y`, same replacement as before\n    x = pm.HalfNormal.dist(1e-3, name="x")\n    neg_x = -x\n    y = pm.Uniform.dist(neg_x, x, name="y")\n    y_value = y.clone()\n    replacements = {y: neg_x + y_value}\n    [new_y] = replace_vars_in_graphs([y], replacements=replacements)\n    assert np.abs(new_y.eval({y_value: 0})) < 1\n    # Confirm that `x` and `neg_x` are still in the graph of `new_y` and that we can impute either\n    assert new_y.eval({x: 100, y_value: 1}) == -99\n    assert new_y.eval({neg_x: 100, y_value: 1}) == 101\n    assert np.abs(x.eval()) < 1\n    # In this case the original `y` is not altered, because we did not replace `x`\n    assert np.abs(y.eval()) < 1\n\n    # Replacement introduces equivalent but not identical operations\n    x = pm.HalfNormal.dist(1e-3, name="x")\n    neg_x = -x\n    neg_x.name = "neg_x"\n    y = pm.Uniform.dist(neg_x, x, name="y")\n    x_value = x.clone()\n    y_value = y.clone()\n    # We clone neg_x!\n    replacements = {x: x_value, y: neg_x.owner.clone().outputs[0] + y_value}\n    [new_x, new_y] = replace_vars_in_graphs([x, y], replacements=replacements)\n    assert new_x.eval({x_value: 100}) == 100\n    assert new_y.eval({x_value: 100, y_value: 1}) == -99\n    # This now fails because the original `neg_x` is not in the replaced graph!\n    with pytest.raises(UnusedInputError, match="neg_x"):\n        new_y.eval({neg_x: 100, y_value: 1})\n    # We can retrieve the cloned variable by name\n    assert new_y.eval({"neg_x": 100, y_value: 1}) == 101\n    assert np.abs(x.eval()) < 1\n    # Confirm the original `y` variable is not changed in place\n    assert np.abs(y.eval()) < 1\n\n\n@pytest.mark.filterwarnings("error")\n@pytest.mark.parametrize("func", (hessian, hessian_diag))\ndef test_hessian_sign_change_warning(func):\n    x = pt.vector("x")\n    f = (x**2).sum()\n    with pytest.warns(\n        FutureWarning,\n        match="will stop negating the output",\n    ):\n        res_neg = func(f, vars=[x])\n    res = func(f, vars=[x], negate_output=False)\n    assert equal_computations([res_neg], [-res])\n\n\ndef test_point_func():\n    x, y = pt.vectors("x", "y")\n    outs = x * 2 + y**2\n    f = compile([x, y], outs)\n\n    point_f = PointFunc(f)\n    np.testing.assert_allclose(point_f({"y": [3], "x": [2]}), [4 + 9])\n\n    # Check we can access other methods of the wrapped pytensor function\n    dprint_res = point_f.dprint(file="str")\n    expected_dprint_res = point_f.f.dprint(file="str")\n    assert dprint_res == expected_dprint_res\n',
        }
